    const g=(i,j)=>{ const v=c[i+','+j]; return (v==null) ? baseRGB : _rgb(v); };
    const c00=g(i0,j0), c10=g(i0+1,j0), c01=g(i0,j0+1), c11=g(i0+1,j0+1), out=[0,0,0];
